import { z } from "zod";

export const registrationSchema = z.object({
  username: z.string().min(3, "Username deve essere lungo almeno 3 caratteri"),
  email: z.string().email("Email non valida"),
  role: z.enum(["user", "admin", "contributor"]),
  otherInfo: z.string().optional(),
  newsletter: z.boolean().optional(),
  frequency: z.enum(["daily", "weekly", "monthly"]).optional(),
  bio: z.string().optional(),
}).superRefine((data, ctx) => {
  // OtherInfo is required when role is "contributor"
  if (data.role === "contributor" && (!data.otherInfo || data.otherInfo.trim() === "")) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      path: ["otherInfo"],
      message: "Altre informazioni sono richieste per contributor",
    });
  }

  // Frequency is required when newsletter is true
  if (data.newsletter === true && (!data.frequency || data.frequency.trim() === "")) {
    ctx.addIssue({
      code: z.ZodIssueCode.custom,
      path: ["frequency"],
      message: "La frequenza è richiesta quando si è iscritti alla newsletter",
    });
  }
});

export type RegistrationFormValues = z.infer<typeof registrationSchema>;

export const roleOptions = [
  { value: "user", label: "User" },
  { value: "admin", label: "Admin" },
  { value: "contributor", label: "Contributor" },
] as const;

export const frequencyOptions = [
  { value: "daily", label: "Giornaliera" },
  { value: "weekly", label: " Settimanale" },
  { value: "monthly", label: "Mensile" },
] as const;

